import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import useTheme from '../customhook/useTheme'

const API_URL = 'http://localhost:5000/hospitalmanagement'
const CITY_API_URL = 'http://localhost:5000/city/getcity'

const emptyForm = {
  name: '',
  email: '',
  address: '',
  pincode: '',
  speciality: '',
  contact: '',
  numberOfDoctors: '',
  numberOfBeds: '',
  openingTime: '',
  closingTime: '',
  rating: '',
  establishedYear: '',
  description: '',
  images: [''],
  emergencyAvailable: false,
  ambulanceService: false,
}

const AddHospital = () => {
  const navigate = useNavigate()
  const { theme, toggleTheme } = useTheme()
  const [message, setMessage] = useState('')
  const [loading, setLoading] = useState(false)
  const [form, setForm] = useState(emptyForm)
  const [cities, setCities] = useState([])

  useEffect(() => {
    const getCities = async () => {
      try {
        const response = await fetch(CITY_API_URL)
        const data = await response.json()
        setCities(data.cities || [])
      } catch (error) {
        setMessage('City data could not be loaded')
        console.error(error)
      }
    }

    getCities()
  }, [])

  const selectedCity = cities.find((item) => item._id === form.address)

  const handleChange = (event) => {
    const { name, value, type, checked } = event.target
    setForm({ ...form, [name]: type === 'checkbox' ? checked : value })
  }

  const handleImageChange = (event, index) => {
    const file = event.target.files?.[0]

    if (!file) {
      return
    }

    if (!file.type.startsWith('image/')) {
      setMessage('Please select a valid image file')
      return
    }

    const reader = new FileReader()
    reader.onloadend = () => {
      const newImages = [...form.images]
      newImages[index] = reader.result
      setForm({ ...form, images: newImages })
    }
    reader.readAsDataURL(file)
  }

  const addImageInput = () => {
    setForm({ ...form, images: [...form.images, ''] })
  }

  const removeImageInput = (index) => {
    if (form.images.length === 1) {
      setForm({ ...form, images: [''] })
      return
    }

    setForm({ ...form, images: form.images.filter((_, imageIndex) => imageIndex !== index) })
  }

  const handleSubmit = async (event) => {
    event.preventDefault()
    setMessage('')

    if (!form.name || !form.email || !form.address || !form.pincode || !form.speciality || !form.contact) {
      setMessage('Please fill all required fields')
      return
    }
    try {
      setLoading(true)
      const response = await fetch(`${API_URL}/add`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...form,
          images: form.images.filter(Boolean),
          numberOfDoctors: Number(form.numberOfDoctors || 0),
          numberOfBeds: Number(form.numberOfBeds || 0),
          rating: form.rating ? Number(form.rating) : undefined,
          establishedYear: form.establishedYear ? Number(form.establishedYear) : undefined,
        }),
      })

      const data = await response.json()
      setMessage(data.message)

      if (response.ok) {
        alert('Hospital added successfully')
        setForm(emptyForm)
      } else {
        alert(data.message)
      }
    } catch (error) {
      setMessage('Hospital could not be added')
      alert('Hospital could not be added')
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  return (
    <main className="page-shell">
      <div className="page-header">
        <div>
          <p className="eyebrow">Hospital</p>
          <h1>Add Hospital</h1>
          <p className="muted">Create a hospital record with contact and facility details.</p>
        </div>
        <div className="header-actions">
          <button className="secondary-btn" onClick={() => navigate(-1)}>Back</button>
          <button className="theme-btn" onClick={toggleTheme} title="Change theme">
            {theme === 'light' ? '☾' : '☀'}
          </button>
        </div>
      </div>

      <form className="hospital-form" onSubmit={handleSubmit}>
        <input name="name" placeholder="Hospital name *" value={form.name} onChange={handleChange} />
        <input name="email" type="email" placeholder="Hospital email *" value={form.email} onChange={handleChange} />
        <input name="speciality" placeholder="Speciality *" value={form.speciality} onChange={handleChange} />
        <input name="contact" type="number" placeholder="Contact number *" value={form.contact} onChange={handleChange} />
        <select name="address" value={form.address} onChange={handleChange}>
          <option value="">Select city *</option>
          {cities.map((item) => (
            <option key={item._id} value={item._id}>{item.city}</option>
          ))}
        </select>
        <input value={selectedCity?.district?.district || ''} placeholder="District" readOnly />
        <input value={selectedCity?.state?.state || ''} placeholder="State" readOnly />
        <input name="pincode" placeholder="Pincode *" value={form.pincode} onChange={handleChange} />
        <input name="numberOfDoctors" type="number" min="0" placeholder="Number of doctors" value={form.numberOfDoctors} onChange={handleChange} />
        <input name="numberOfBeds" type="number" min="0" placeholder="Number of beds" value={form.numberOfBeds} onChange={handleChange} />
        <input name="openingTime" type="time" value={form.openingTime} onChange={handleChange} />
        <input name="closingTime" type="time" value={form.closingTime} onChange={handleChange} />
        <input name="rating" type="number" min="1" max="5" placeholder="Rating 1 to 5" value={form.rating} onChange={handleChange} />
        <input name="establishedYear" type="number" min="1900" placeholder="Established year" value={form.establishedYear} onChange={handleChange} />

        <label className="check-field">
          <input name="emergencyAvailable" type="checkbox" checked={form.emergencyAvailable} onChange={handleChange} />
          Emergency available
        </label>
        <label className="check-field">
          <input name="ambulanceService" type="checkbox" checked={form.ambulanceService} onChange={handleChange} />
          Ambulance service
        </label>

        <textarea name="description" placeholder="Description" value={form.description} onChange={handleChange} />

        <div className="hospital-image-box">
          <div className="hospital-image-head">
            <span>Hospital images</span>
            <button type="button" className="add-symbol-btn" onClick={addImageInput} title="Add image">+</button>
          </div>

          {form.images.map((image, index) => (
            <div className="hospital-image-row" key={index}>
              <input type="file" accept="image/*" onChange={(event) => handleImageChange(event, index)} />
              <button type="button" className="icon-btn delete-icon" onClick={() => removeImageInput(index)} title="Remove image">-</button>
              {image && <img src={image} alt={`Hospital ${index + 1}`} />}
            </div>
          ))}
        </div>

        <div className="form-actions hospital-actions">
          <button type="submit" disabled={loading}>{loading ? 'Saving...' : 'Add Hospital'}</button>
          <button type="button" className="secondary-btn" onClick={() => navigate(-1)}>Cancel</button>
        </div>
      </form>

      {message && <p className="message profile-message">{message}</p>}
    </main>
  )
}

export default AddHospital

import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import useTheme from '../customhook/useTheme'

const API_URL = 'http://localhost:5000/hospital'

const AdminProfile = () => {
  const navigate = useNavigate()
  const { theme, toggleTheme } = useTheme()
  const token = localStorage.getItem('token')

  const [user, setUser] = useState({})
  const [edit, setEdit] = useState(false)
  const [message, setMessage] = useState('')
  const [passwordBox, setPasswordBox] = useState(false)
  const [passwordForm, setPasswordForm] = useState({
    oldPassword: '',
    newPassword: '',
  })
  const [form, setForm] = useState({
    name: '',
    email: '',
    phone: '',
    age: '',
    gender: '',
    BG: '',
    image: '',
  })

  const getProfile = async () => {
    if (!token) { navigate('/'); return }
    try {
      const response = await fetch(`${API_URL}/profile`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      const data = await response.json()

      if (response.ok) {
        setUser(data.user)
        setForm({
          name: data.user.name,
          email: data.user.email,
          phone: data.user.phone,
          age: data.user.age,
          gender: data.user.gender,
          BG: data.user.BG,
          image: data.user.image || '',
        })
      } else {
        setMessage(data.message)
      }
    } catch (error) {
      setMessage('Profile could not be loaded')
      console.error(error)
    }
  }

  useEffect(() => {
    getProfile()
  }, [])

  const handleChange = (event) => {
    setForm({ ...form, [event.target.name]: event.target.value })
  }

  const handlePasswordChange = (event) => {
    setPasswordForm({ ...passwordForm, [event.target.name]: event.target.value })
  }

  const handleImageChange = (event) => {
    const file = event.target.files[0]
    if (!file) return

    const reader = new FileReader()
    reader.onloadend = () => {
      setForm({ ...form, image: reader.result })
    }
    reader.readAsDataURL(file)
  }

  const handleSubmit = async (event) => {
    event.preventDefault()

    if (!form.name || !form.email || !form.phone || !form.age || !form.gender || !form.BG) {
      setMessage('All fields are required')
      return
    }

    try {
      const response = await fetch(`${API_URL}/updateprofile`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(form),
      })
      const data = await response.json()

      setMessage(data.message)
      if (response.ok) {
        alert('Profile updated successfully')
        setEdit(false)
        getProfile()
      } else {
        alert(data.message)
      }
    } catch (error) {
      setMessage('Profile could not be updated')
      alert('Profile could not be updated')
      console.error(error)
    }
  }

  const logout = () => {
    const confirmLogout = window.confirm('Are you sure you want to logout?')
    if (!confirmLogout) return

    localStorage.removeItem('token')
    alert('Logout successfully')
    navigate('/')
  }

  const resetPassword = async (event) => {
    event.preventDefault()

    if (!passwordForm.oldPassword || !passwordForm.newPassword) {
      setMessage('Old password and new password are required')
      return
    }

    try {
      const response = await fetch(`${API_URL}/changepassword`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(passwordForm),
      })
      const data = await response.json()
      setMessage(data.message)

      if (response.ok) {
        alert('Password changed successfully')
        setPasswordForm({ oldPassword: '', newPassword: '' })
        setPasswordBox(false)
      } else {
        alert(data.message)
      }
    } catch (error) {
      setMessage('Password could not be changed')
      console.error(error)
    }
  }

  return (
    <main className="page-shell">
      <div className="page-header">
        <div>
          <p className="eyebrow">Account</p>
          <h1>Profile</h1>
          <p className="muted">Your profile details</p>
        </div>

        <div className="header-actions">
          <button className="secondary-btn" onClick={() => navigate(-1)}>Back</button>
          <button className="theme-btn" onClick={toggleTheme} title="Change theme">
            {theme === 'light' ? '☾' : '☀'}
          </button>
          <button className="secondary-btn" onClick={() => setEdit(true)}>Edit</button>
          <button className="secondary-btn" onClick={() => setPasswordBox(true)}>Reset Password</button>
          <button className="danger-btn" onClick={logout}>Logout</button>
        </div>
      </div>

      <section className="profile-card">
        <div className="profile-top">
          <div className="profile-avatar">
            {user.image ? <img src={user.image} alt="Profile" /> : (user.name || 'U').charAt(0).toUpperCase()}
          </div>
          <div>
            <h2>{user.name || 'User'}</h2>
            <p>{user.email || 'No email'}</p>
          </div>
        </div>

        {!edit && (
          <div className="profile-grid">
            <div className="profile-info">
              <span>Name</span>
              <strong>{user.name || '-'}</strong>
            </div>
            <div className="profile-info">
              <span>Email</span>
              <strong>{user.email || '-'}</strong>
            </div>
            <div className="profile-info">
              <span>Phone</span>
              <strong>{user.phone || '-'}</strong>
            </div>
            <div className="profile-info">
              <span>Age</span>
              <strong>{user.age || '-'}</strong>
            </div>
            <div className="profile-info">
              <span>Gender</span>
              <strong>{user.gender || '-'}</strong>
            </div>
            <div className="profile-info">
              <span>Blood Group</span>
              <strong>{user.BG || '-'}</strong>
            </div>
          </div>
        )}

        {edit && (
          <form className="profile-form" onSubmit={handleSubmit}>
            <input name="name" type="text" placeholder="Name" value={form.name} onChange={handleChange} />
            <input name="email" type="email" placeholder="Email" value={form.email} onChange={handleChange} />
            <input name="phone" type="number" placeholder="Phone" value={form.phone} onChange={handleChange} />
            <input name="age" type="number" placeholder="Age" value={form.age} onChange={handleChange} />
            <select name="gender" value={form.gender} onChange={handleChange}>
              <option value="">Select gender</option>
              <option value="male">Male</option>
              <option value="female">Female</option>
              <option value="other">Other</option>
            </select>
            <input name="BG" type="text" placeholder="Blood Group" value={form.BG} onChange={handleChange} />
            <input name="image" type="file" accept="image/*" onChange={handleImageChange} />

            <div className="form-actions">
              <button type="submit">Save</button>
              <button type="button" className="secondary-btn" onClick={() => setEdit(false)}>Cancel</button>
            </div>
          </form>
        )}

        {passwordBox && (
          <form className="profile-form" onSubmit={resetPassword}>
            <input name="oldPassword" type="password" placeholder="Old password" value={passwordForm.oldPassword} onChange={handlePasswordChange} />
            <input name="newPassword" type="password" placeholder="New password" value={passwordForm.newPassword} onChange={handlePasswordChange} />
            <div className="form-actions">
              <button type="submit">Change Password</button>
              <button type="button" className="secondary-btn" onClick={() => setPasswordBox(false)}>Cancel</button>
            </div>
          </form>
        )}

        {message && <p className="message profile-message">{message}</p>}
      </section>
    </main>
  )
}

export default AdminProfile

import React from 'react'
import { useLocation, useNavigate } from 'react-router-dom'
import useTheme from '../customhook/useTheme'

const AdminSidebar = () => {
  const navigate = useNavigate()
  const location = useLocation()
  const { theme, toggleTheme } = useTheme()
  const user = JSON.parse(localStorage.getItem('user') || '{}')
  const name = user.name || 'Admin'
  const email = user.email || 'admin panel'

  const menuItems = [
    { path: '/home', icon: 'D', label: 'Dashboard' },
    { path: '/state', icon: 'S', label: 'State' },
    { path: '/district', icon: 'D', label: 'District' },
    { path: '/city', icon: 'C', label: 'City' },
    { path: '/showhospitals', icon: 'H', label: 'Hospitals' },
    { path: '/adminreport', icon: 'R', label: 'Reports' },
  ]

  return (
    <aside className="hospital-sidebar">
      <div>
        <p className="eyebrow">Admin</p>
        <h2>Admin Panel</h2>
      </div>

      <button
        className={location.pathname === '/profile' ? 'hospital-sidebar-profile profile-active' : 'hospital-sidebar-profile'}
        onClick={() => navigate('/profile')}
      >
        <span className="hospital-sidebar-avatar">
          {user.image ? <img src={user.image} alt={name} /> : name.charAt(0).toUpperCase()}
        </span>
        <span className="hospital-sidebar-profile-text">
          <b>{name}</b>
          <small>{email}</small>
        </span>
      </button>

      <nav className="hospital-menu">
        {menuItems.map((item) => (
          <button
            className={location.pathname === item.path ? 'menu-active' : ''}
            key={item.path}
            onClick={() => navigate(item.path)}
          >
            <span>{item.icon}</span>
            {item.label}
          </button>
        ))}
        <button onClick={toggleTheme}>
          <span>{theme === 'light' ? 'D' : 'L'}</span>
          {theme === 'light' ? 'Dark' : 'Light'}
        </button>
      </nav>
    </aside>
  )
}

export default AdminSidebar

import React, { useEffect, useState } from 'react'
import { jsPDF } from 'jspdf'
import AdminSidebar from './AdminSidebar'

const API_URL = 'http://localhost:5000'

const Adminreport = () => {
  const [states, setStates] = useState([])
  const [districts, setDistricts] = useState([])
  const [cities, setCities] = useState([])
  const [hospitals, setHospitals] = useState([])
  const [search, setSearch] = useState('')
  const [sortBy, setSortBy] = useState('name')
  const [loading, setLoading] = useState(true)
  const [message, setMessage] = useState('')

  const getData = async () => {
    try {
      setLoading(true)
      const token = localStorage.getItem('token')

      const stateResponse = await fetch(`${API_URL}/state/getstate`)
      const districtResponse = await fetch(`${API_URL}/district/getdistrict`)
      const cityResponse = await fetch(`${API_URL}/city/getcity`)
      const hospitalResponse = await fetch(`${API_URL}/hospitalmanagement/get`, {
        headers: { Authorization: `Bearer ${token}` },
      })

      const stateData = await stateResponse.json()
      const districtData = await districtResponse.json()
      const cityData = await cityResponse.json()
      const hospitalData = await hospitalResponse.json()

      setStates(stateData.states || [])
      setDistricts(districtData.districts || [])
      setCities(cityData.cities || [])
      setHospitals(hospitalData.hospitals || [])
      setMessage('Admin reports loaded successfully')
    } catch (error) {
      setMessage('Reports load nahi ho payi')
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getData()
  }, [])

  const downloadPdf = (title, cards, rows = []) => {
    const pdf = new jsPDF()
    let y = 18

    pdf.setFontSize(18)
    pdf.text(title, 14, y)
    y += 8

    pdf.setFontSize(10)
    pdf.text(`Generated on ${new Date().toLocaleString()}`, 14, y)
    y += 12

    cards.forEach((card) => {
      pdf.setFontSize(11)
      pdf.text(`${card.label}: ${card.value}`, 14, y)
      y += 8
    })

    if (rows.length > 0) {
      y += 6
      rows.forEach((row) => {
        if (y > 280) {
          pdf.addPage()
          y = 18
        }

        const lines = pdf.splitTextToSize(row, 180)
        pdf.text(lines, 14, y)
        y += lines.length * 7
      })
    }

    const fileName = title.toLowerCase().replaceAll(' ', '-') + '.pdf'
    pdf.save(fileName)
  }

  const summaryCards = [
    { label: 'States', value: states.length },
    { label: 'Districts', value: districts.length },
    { label: 'Cities', value: cities.length },
    { label: 'Hospitals', value: hospitals.length },
  ]

  const getCity = (item) => item.address?.city || item.cityId?.city || item.city || '-'
  const getDistrict = (item) => item.address?.district?.district || item.districtId?.district || item.district || '-'
  const getState = (item) => item.address?.state?.state || item.stateId?.state || item.state || '-'
  const getPhone = (item) => item.contact || item.phone || '-'

  const searchText = search.toLowerCase().trim()
  const filteredHospitals = hospitals
    .filter((item) => {
      if (!searchText) return true

      const text = [
        item.name,
        item.email,
        getPhone(item),
        getCity(item),
        getDistrict(item),
        getState(item),
      ].join(' ').toLowerCase()

      return text.includes(searchText)
    })
    .sort((a, b) => {
      if (sortBy === 'city') {
        return getCity(a).localeCompare(getCity(b))
      }

      if (sortBy === 'state') {
        return getState(a).localeCompare(getState(b))
      }

      return (a.name || '').localeCompare(b.name || '')
    })

  return (
    <main className="hospital-dash-layout">
      <AdminSidebar />

      <section className="hospital-main report-main-scroll">
        <header className="hospital-topbar">
          <div>
            <p className="eyebrow">Admin</p>
            <h1>Admin Reports</h1>
            <p className="muted">Master data and hospital summary report.</p>
          </div>
          <button className="secondary-btn" onClick={getData}>Refresh</button>
        </header>

        <div className="hospital-toolbar">
          <input
            type="text"
            placeholder="Search hospital, city, district or state"
            value={search}
            onChange={(event) => setSearch(event.target.value)}
          />
          <select value={sortBy} onChange={(event) => setSortBy(event.target.value)}>
            <option value="name">Hospital name</option>
            <option value="city">City name</option>
            <option value="state">State name</option>
          </select>
        </div>

        <section className="report-page-card">
          <div className="report-head">
            <div>
              <h2>Admin Report</h2>
              <p className="muted">Master data and hospital summary with PDF download.</p>
            </div>
          </div>

          {message && <p className="message">{message}</p>}

          {loading && (
            <div className="empty-state">
              <h2>Loading reports...</h2>
              <p className="muted">Please wait.</p>
            </div>
          )}

          {!loading && (
            <>
              <article className="report-box">
                <div className="report-box-head">
                  <div>
                    <p className="eyebrow">Overview</p>
                    <h2>Master Data Summary</h2>
                    <p className="muted">State, district, city, and hospital counts.</p>
                  </div>
                  <button className="download-btn" onClick={() => downloadPdf('Admin Master Data Summary', summaryCards)}>↓</button>
                </div>

                <div className="report-stat-grid">
                  {summaryCards.map((card) => (
                    <div className="report-stat-card" key={card.label}>
                      <span>{card.label}</span>
                      <strong>{card.value}</strong>
                    </div>
                  ))}
                </div>
              </article>

              <article className="report-box">
                <div className="report-box-head">
                  <div>
                    <p className="eyebrow">Hospitals</p>
                    <h2>Hospital List Report</h2>
                    <p className="muted">Hospitals filtered by search and sort.</p>
                  </div>
                  <button
                    className="download-btn"
                    onClick={() => downloadPdf(
                      'Admin Hospital List Report',
                      [{ label: 'Total Hospitals', value: filteredHospitals.length }],
                      filteredHospitals.map((item) => `${item.name || 'Hospital'} | ${item.email || '-'} | ${getPhone(item)} | ${getCity(item)} | ${getDistrict(item)} | ${getState(item)}`)
                    )}
                  >
                    ↓
                  </button>
                </div>

                {filteredHospitals.length === 0 ? (
                  <div className="empty-state">
                    <h2>No hospital found</h2>
                    <p className="muted">No hospital matches your search.</p>
                  </div>
                ) : (
                  <div className="table-wrap report-table-wrap">
                    <table className="report-data-table">
                      <thead>
                        <tr>
                          <th>#</th>
                          <th>Hospital</th>
                          <th>Email</th>
                          <th>Phone</th>
                          <th>City</th>
                          <th>District</th>
                          <th>State</th>
                        </tr>
                      </thead>
                      <tbody>
                        {filteredHospitals.map((item, index) => (
                          <tr key={item._id}>
                            <td>{index + 1}</td>
                            <td>{item.name || '-'}</td>
                            <td>{item.email || '-'}</td>
                            <td>{getPhone(item)}</td>
                            <td>{getCity(item)}</td>
                            <td>{getDistrict(item)}</td>
                            <td>{getState(item)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </article>
            </>
          )}
        </section>
      </section>
    </main>
  )
}

export default Adminreport

