        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(form),
      })
      const data = await response.json()
      setMessage(data.message)

      if (response.ok) {
        alert('Profile updated successfully')
        setEdit(false)
        getProfile()
      } else {
        alert(data.message)
      }
